class Solution {
    public int largestInteger(int num) {
        char[] chars = String.valueOf(num).toCharArray();
        int[] even = new int[chars.length];
        int[] odd = new int[chars.length];
        int evenIndex = 0, oddIndex = 0;
        for (int i = 0; i < chars.length; i++) {
            if ((chars[i] - '0') % 2 == 0) {
                even[evenIndex++] = chars[i] - '0';
            } else {
                odd[oddIndex++] = chars[i] - '0';
            }
        }
        Arrays.sort(even, 0, evenIndex);
        Arrays.sort(odd, 0, oddIndex);
        for (int i = 0; i < chars.length; i++) {
            if ((chars[i] - '0') % 2 == 0) {
                chars[i] = (char) (even[--evenIndex] + '0');
            } else {
                chars[i] = (char) (odd[--oddIndex] + '0');
            }
        }
        return Integer.parseInt(new String(chars));
    }
}
